import pyotp
import qrcode
import io
import base64
from datetime import datetime
import hashlib
import hmac
import struct
import time


class TOTPAuthenticator:
    def __init__(self, issuer_name="MyApp"):
        self.issuer_name = issuer_name
    
    def generate_secret(self):
        """Generate a new TOTP secret for a user"""
        return pyotp.random_base32()
    
    def get_provisioning_uri(self, secret, user_email):
        """Generate provisioning URI for authenticator apps"""
        totp = pyotp.TOTP(secret)
        return totp.provisioning_uri(
            name=user_email,
            issuer_name=self.issuer_name
        )
    
    def generate_qr_code(self, secret, user_email):
        """Generate QR code for the TOTP secret"""
        uri = self.get_provisioning_uri(secret, user_email)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        buffer = io.BytesIO()
        img.save(buffer, format='PNG')
        buffer.seek(0)
        
        return buffer
    
    def generate_qr_code_base64(self, secret, user_email):
        """Generate QR code as base64 string for web display"""
        buffer = self.generate_qr_code(secret, user_email)
        img_base64 = base64.b64encode(buffer.getvalue()).decode()
        return f"data:image/png;base64,{img_base64}"
    
    def verify_totp(self, secret, token, valid_window=1):
        """
        Verify TOTP token
        valid_window: number of time steps to check before and after current time
        """
        totp = pyotp.TOTP(secret)
        return totp.verify(token, valid_window=valid_window)
    
    def get_current_totp(self, secret):
        """Get current TOTP code (for testing purposes)"""
        totp = pyotp.TOTP(secret)
        return totp.now()
    
    def verify_totp_manual(self, secret, token, time_step=30, valid_window=1):
        """
        Manual TOTP verification implementation
        Validates token against current time and adjacent time windows
        """
        current_time = int(time.time())
        
        for i in range(-valid_window, valid_window + 1):
            time_counter = (current_time + (i * time_step)) // time_step
            expected_token = self._generate_totp_token(secret, time_counter)
            
            if self._constant_time_compare(token, expected_token):
                return True
        
        return False
    
    def _generate_totp_token(self, secret, time_counter, digits=6):
        """Generate TOTP token for a specific time counter"""
        key = base64.b32decode(secret, casefold=True)
        
        msg = struct.pack(">Q", time_counter)
        
        hmac_hash = hmac.new(key, msg, hashlib.sha1).digest()
        
        offset = hmac_hash[-1] & 0x0F
        
        truncated_hash = struct.unpack(">I", hmac_hash[offset:offset + 4])[0]
        truncated_hash &= 0x7FFFFFFF
        
        token = truncated_hash % (10 ** digits)
        
        return str(token).zfill(digits)
    
    def _constant_time_compare(self, val1, val2):
        """Constant time string comparison to prevent timing attacks"""
        if len(val1) != len(val2):
            return False
        
        result = 0
        for x, y in zip(val1, val2):
            result |= ord(x) ^ ord(y)
        
        return result == 0
    
    def get_remaining_seconds(self):
        """Get remaining seconds until next TOTP code"""
        return 30 - (int(time.time()) % 30)


class UserTOTPManager:
    def __init__(self, issuer_name="MyApp"):
        self.authenticator = TOTPAuthenticator(issuer_name)
        self.users = {}
    
    def register_user(self, user_id, user_email):
        """Register a new user and generate TOTP secret"""
        secret = self.authenticator.generate_secret()
        
        self.users[user_id] = {
            'email': user_email,
            'secret': secret,
            'enabled': False,
            'backup_codes': self._generate_backup_codes()
        }
        
        return {
            'secret': secret,
            'qr_code': self.authenticator.generate_qr_code_base64(secret, user_email),
            'provisioning_uri': self.authenticator.get_provisioning_uri(secret, user_email)
        }
    
    def enable_totp(self, user_id, verification_token):
        """Enable TOTP for user after verifying initial token"""
        if user_id not in self.users:
            return False
        
        user = self.users[user_id]
        
        if self.authenticator.verify_totp(user['secret'], verification_token):
            user['enabled'] = True
            return True
        
        return False
    
    def verify_user_token(self, user_id, token):
        """Verify TOTP token for a user"""
        if user_id not in self.users:
            return False
        
        user = self.users[user_id]
        
        if not user['enabled']:
            return False
        
        if self.authenticator.verify_totp(user['secret'], token):
            return True
        
        if token in user['backup_codes']:
            user['backup_codes'].remove(token)
            return True
        
        return False
    
    def disable_totp(self, user_id):
        """Disable TOTP for a user"""
        if user_id in self.users:
            self.users[user_id]['enabled'] = False
            return True
        return False
    
    def regenerate_secret(self, user_id):
        """Regenerate TOTP secret for a user"""
        if user_id not in self.users:
            return None
        
        user = self.users[user_id]
        secret = self.authenticator.generate_secret()
        user['secret'] = secret
        user['enabled'] = False
        
        return {
            'secret': secret,
            'qr_code': self.authenticator.generate_qr_code_base64(secret, user['email']),
            'provisioning_uri': self.authenticator.get_provisioning_uri(secret, user['email'])
        }
    
    def _generate_backup_codes(self, count=10):
        """Generate backup codes for account recovery"""
        import secrets
        return [secrets.token_hex(4).upper() for _ in range(count)]
    
    def get_backup_codes(self, user_id):
        """Get backup codes for a user"""
        if user_id in self.users:
            return self.users[user_id]['backup_codes']
        return []
    
    def regenerate_backup_codes(self, user_id):
        """Regenerate backup codes for a user"""
        if user_id in self.users:
            self.users[user_id]['backup_codes'] = self._generate_backup_codes()
            return self.users[user_id]['backup_codes']
        return []


def save_qr_code_to_file(authenticator, secret, user_email, filename):
    """Save QR code to a file"""
    qr_buffer = authenticator.generate_qr_code(secret, user_email)
    with open(filename, 'wb') as f:
        f.write(qr_buffer.getvalue())


